const SidebarWithSubmenu = () => {
  const [isOpen, setIsOpen] = useState(false)

  const itemsSubmenu: SubmenuItemProps[] = (
    [
      {
        type: 'row',
        text: 'Tab 1.1',
        content: 'Content 1.1',
        key: 'tab-1-1'
      },
      {
        type: 'row',
        text: 'Tab 1.2',
        content: 'Content 1.2',
        key: 'tab-1-2'
      }
    ]
  )

  return (
    <>
      <Button onClick={() => setIsOpen(true)}>
        Open
      </Button>
      <Sidebar
        visible={isOpen}
        onClose={() => setIsOpen(false)}
        noPaddingContent
        title="Sidebar"
        size="large"
      >
        <Submenu items={itemsSubmenu} />
      </Sidebar>
    </>
  )
}
